mapper.select:
SELECT count(*)
FROM notifications

    AND customer_id = #{customerId}
    AND channel = #{channel}
    AND template_id = #{templateId}
    AND recipient_address = #{recipientAddress}
    AND state_id = #{stateId}

SELECT state_id as "stateId", count(*) as "retryCount" FROM notifications
AND state_id = #{stateId}
GROUP BY state_id

SELECT count(*)
FROM notifications
WHERE state_id IN ('FAILED', 'BOUNCED')
AND customer_id = #{customerId}
AND channel = #{channel}

SELECT channel, state_id as "stateId", count(*) as "retryCount" FROM notifications
AND channel = #{channel}
GROUP BY channel, state_id

SELECT count(*)
FROM notifications
WHERE customer_id = #{customerId}
AND state_id = #{stateId}

SELECT count(*)
FROM notifications
WHERE channel = #{channel}
AND state_id = #{stateId}

SELECT count(*)
FROM notifications
WHERE template_id = #{templateId}
AND state_id = #{stateId}
